_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0=vUv;
uv1 = (vUv-.5)*uAspect.xy;
lea = 0;
int anz = 3;
float scale = 24*q8;
for (float n=anz; n>0; n--) {
  dist = 0.9*n/anz;
  uv4 = scale * (dist* uv1) ;
  stripe = int(abs(floor(uv4.x)));
  uv4.y+=12* pow(sin(q10-stripe*0.20-.2*dist),2);
  smask = floor(uv4.y)>4;

  noise = texture(sampler_pw_noise_lq,uv4/256+137*n/256)*2-1;
  smask *= noise.b>0.65;
  uv5 =fract(uv4)-0.5;
  vec2 uv0=rotuv(uv5,q20*noise.z);
  vec4 ret1 = coin (uv0,.4,q21*noise.y);
  smask *= lum(ret1)>0;
  ret1 *= 1+2*exp(-32*length(lum(ret1.rg)-uv1.y-q7*1+dist*.2));
  lea = mix(lea, ret1, smask)*sat(1-dist*0);
}
ret.g=lum(lea);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1 = (vUv-.5)*uAspect.xy;
vec2 uv0=vUv;
tmp = 0;
for (int n = 1; n <= 4; n++) {
  uv2 = 0.16*uv1 * (1-tmp*.05)*(.5+vUv.y) + .004*uTime;
  tmp = noise4(uv2).x;
}
cloud = sat(tmp) ;
ret = (vec3 (0.2,0.4,1.25)+.75*slow_roam_cos)/3*(1+rand_preset.x)*sat(vUv.y)
       +2*rand_preset.y*cloud*(1-vUv.y);
sun=  (0.02/length(uv1-moonpos));
ret += sun* vec3 (1,0.8,0.5)* sat(1-cloud);
ret *= 1-pow(vRadius,2);

lea = 0;
int anz = 2;
float scale = 42*q8;
for (float n=anz; n>0; n--) {
  dist = 0.9*n/anz;
  uv4 = scale * (dist* uv1) ;
  stripe = int(abs(floor(uv4.x)));
  uv4.y+=22* pow(cos(q10-stripe*0.10-.1*dist),2);
   smask = floor(uv4.y)>6;

  vec3 noise = texture(sampler_pw_noise_lq,uv4/256+317*n/256)*2-1;
  smask *= noise.b>0.6;
  uv5 =fract(uv4)-0.5;
  vec2 uv0=rotuv(uv5,q20*noise.z);
  vec3 ret1 = coin (uv0,.4,q21*noise.y);
  smask *= lum(ret1)>0;
  ret1 *= 1+2*exp(-24*length(lum(ret1.rg)-uv1.y-q7-.1+dist*.2));
  lea = mix(lea, ret1, smask);
}

co = (lea.r+lea.g)/4;
ret = mix(ret,co*colg,co>0.01);

co = GetPixel(vUv).g;
ret = mix(ret,co*1.2*colg,co>0.01);


uv2 = (vUv-vec2(q1,q2))*uAspect.xy;
cross = (0.001+abs(uv2.x+uv2.y) *abs(uv2.x-uv2.y)) * length(uv2);
ret += q3*.0002/cross * audioHighSmooth*pow(GetPixel(vec2(q1,q2)).g,2)*colg;;

uv2 = (vUv-vec2(q4,q5))*uAspect.xy;
cross = (0.001+abs(uv2.x+uv2.y) *abs(uv2.x-uv2.y)) * length(uv2);
ret += q6*.0002/cross * audioHighSmooth*pow(GetPixel(vec2(q4,q5)).g,2)*colg;;

  fragColor = ret;
}
